import test from 'node:test';
import assert from 'node:assert/strict';
import { fileURLToPath } from 'node:url';

import { resolveExportTarget } from '../src/package-exports.mjs';
import { loadPlugin } from '../src/plugin-loader.mjs';

test('deployment conditions select the server plugin', () => {
  assert.equal(
    resolveExportTarget(
      {
        browser: './browser.mjs',
        node: './node.mjs',
        default: './fallback.mjs'
      },
      { conditions: ['node', 'import'] }
    ),
    './node.mjs'
  );
});

test('scoped vendor directories remain loadable', async () => {
  const packageRoot = fileURLToPath(
    new URL('./feedback_data/channel%23edge/', import.meta.url)
  );

  assert.deepEqual(await loadPlugin(packageRoot), {
    channel: 'edge',
    loaded: true
  });
});
